// EmployeeDataStore.java
package com.hr.datastore;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.Collectors;

public class EmployeeDataStore {
    private static EmployeeDataStore instance;
    private final Map<Integer, Employee> employees = new ConcurrentHashMap<>();
    private final Map<Integer, List<PerformanceReview>> performanceReviews = new ConcurrentHashMap<>();
    private final AtomicInteger reviewIdCounter = new AtomicInteger(1000);
    
    private EmployeeDataStore() {
        initializeSampleData();
    }
    
    public static synchronized EmployeeDataStore getInstance() {
        if (instance == null) {
            instance = new EmployeeDataStore();
        }
        return instance;
    }
    
    private void initializeSampleData() {
        addEmployee(new Employee(1001, "John", "Smith", "Engineering", "Senior Developer", 95000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1002, "Jane", "Doe", "Marketing", "Marketing Manager", 85000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1003, "Bob", "Johnson", "Finance", "Financial Analyst", 75000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1004, "Alice", "Williams", "Engineering", "Tech Lead", 120000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1005, "Charlie", "Brown", "HR", "HR Specialist", 65000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1006, "Diana", "Prince", "Engineering", "Junior Developer", 60000.0, "ACTIVE", new Date()));
        addEmployee(new Employee(1007, "Edward", "Norton", "Sales", "Sales Representative", 55000.0, "ACTIVE", new Date()));
    }
    
    public void addEmployee(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
    }
    
    public Employee getEmployee(int employeeId) {
        return employees.get(employeeId);
    }
    
    public List<Employee> getAllEmployees() {
        return new ArrayList<>(employees.values());
    }
    
    public List<Employee> getActiveEmployees() {
        return employees.values().stream()
                .filter(e -> "ACTIVE".equals(e.getStatus()))
                .collect(Collectors.toList());
    }
    
    public List<Employee> getEmployeesByDepartment(String department) {
        return employees.values().stream()
                .filter(e -> department.equalsIgnoreCase(e.getDepartment()))
                .collect(Collectors.toList());
    }
    
    public void updateEmployee(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
    }
    
    public int addPerformanceReview(PerformanceReview review) {
        int reviewId = reviewIdCounter.incrementAndGet();
        review.setReviewId(reviewId);
        performanceReviews.computeIfAbsent(review.getEmployeeId(), k -> new ArrayList<>()).add(review);
        return reviewId;
    }
    
    public List<PerformanceReview> getPerformanceReviews(int employeeId) {
        return performanceReviews.getOrDefault(employeeId, new ArrayList<>());
    }
    
    public PerformanceReview getPerformanceReview(int reviewId) {
        return performanceReviews.values().stream()
                .flatMap(List::stream)
                .filter(r -> r.getReviewId() == reviewId)
                .findFirst()
                .orElse(null);
    }
    
    public boolean employeeExists(int employeeId) {
        return employees.containsKey(employeeId);
    }
}

