// EmployeeManagementServiceImpl.java
package com.hr.service;

import com.hr.datastore.EmployeeDataStore;
import com.hr.exception.EmployeeManagementFault;
import com.hr.exception.EmployeeManagementFault.FaultInfo;
import com.hr.model.*;

import javax.jws.WebService;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    endpointInterface = "com.hr.service.EmployeeManagementService",
    serviceName = "EmployeeManagementWebService",
    portName = "EmployeeManagementPort",
    targetNamespace = "http://hr.com/employee-management",
    wsdlLocation = "EmployeeManagementService.wsdl"
)
public class EmployeeManagementServiceImpl implements EmployeeManagementService {
    
    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private static final double MAX_SALARY = 500000.0;
    private static final double MIN_SALARY = 30000.0;
    private static final double MAX_RAISE_PERCENTAGE = 50.0;
    
    private final EmployeeDataStore dataStore = EmployeeDataStore.getInstance();

    @Override
    public Employee getEmployee(int employeeId) throws EmployeeManagementFault {
        LOGGER.info("Retrieving employee with ID: " + employeeId);
        validateEmployeeExists(employeeId);
        return dataStore.getEmployee(employeeId);
    }

    @Override
    public List<Employee> getAllActiveEmployees() {
        LOGGER.info("Retrieving all active employees");
        return dataStore.getActiveEmployees();
    }

    @Override
    public List<Employee> getEmployeesByDepartment(String department) {
        LOGGER.info("Retrieving employees in department: " + department);
        if (department == null || department.trim().isEmpty()) {
            return new ArrayList<>();
        }
        return dataStore.getEmployeesByDepartment(department);
    }

    @Override
    public SalaryUpdateResult updateSalary(int employeeId, double newSalary, String reason) 
            throws EmployeeManagementFault {
        LOGGER.info("Updating salary for employee " + employeeId + " to " + newSalary);
        
        validateEmployeeExists(employeeId);
        validateEmployeeActive(employeeId);
        validateSalary(newSalary);
        
        if (reason == null || reason.trim().isEmpty()) {
            throw new EmployeeManagementFault("Reason is required for salary updates",
                new FaultInfo("INVALID_REASON", "A reason must be provided for salary changes"));
        }
        
        Employee employee = dataStore.getEmployee(employeeId);
        double previousSalary = employee.getSalary();
        
        employee.setSalary(newSalary);
        dataStore.updateEmployee(employee);
        
        SalaryUpdateResult result = new SalaryUpdateResult();
        result.setSuccess(true);
        result.setMessage("Salary updated successfully. Reason: " + reason);
        result.setEmployeeId(employeeId);
        result.setPreviousSalary(previousSalary);
        result.setNewSalary(newSalary);
        result.setChangeAmount(newSalary - previousSalary);
        result.setChangePercentage(previousSalary > 0 ? ((newSalary - previousSalary) / previousSalary) * 100 : 0);
        
        LOGGER.info("Salary updated for employee " + employeeId + ": " + previousSalary + " -> " + newSalary);
        return result;
    }

    @Override
    public SalaryUpdateResult updateSalaryByPercentage(int employeeId, double percentageIncrease, String reason) 
            throws EmployeeManagementFault {
        LOGGER.info("Updating salary for employee " + employeeId + " by " + percentageIncrease + "%");
        
        validateEmployeeExists(employeeId);
        validateEmployeeActive(employeeId);
        
        if (percentageIncrease < -50 || percentageIncrease > MAX_RAISE_PERCENTAGE) {
            throw new EmployeeManagementFault("Invalid percentage",
                new FaultInfo("INVALID_PERCENTAGE", 
                    "Salary change percentage must be between -50% and " + MAX_RAISE_PERCENTAGE + "%"));
        }
        
        Employee employee = dataStore.getEmployee(employeeId);
        double previousSalary = employee.getSalary();
        double newSalary = previousSalary * (1 + percentageIncrease / 100.0);
        
        validateSalary(newSalary);
        
        employee.setSalary(newSalary);
        dataStore.updateEmployee(employee);
        
        SalaryUpdateResult result = new SalaryUpdateResult();
        result.setSuccess(true);
        result.setMessage("Salary updated by " + percentageIncrease + "%. Reason: " + reason);
        result.setEmployeeId(employeeId);
        result.setPreviousSalary(previousSalary);
        result.setNewSalary(newSalary);
        result.setChangeAmount(newSalary - previousSalary);
        result.setChangePercentage(percentageIncrease);
        
        return result;
    }

    @Override
    public List<SalaryUpdateResult> applyDepartmentRaise(String department, double percentageIncrease, String reason) 
            throws EmployeeManagementFault {
        LOGGER.info("Applying " + percentageIncrease + "% raise to department: " + department);
        
        if (department == null || department.trim().isEmpty()) {
            throw new EmployeeManagementFault("Department is required",
                new FaultInfo("INVALID_DEPARTMENT", "Department name must be provided"));
        }
        
        if (percentageIncrease <= 0 || percentageIncrease > MAX_RAISE_PERCENTAGE) {
            throw new EmployeeManagementFault("Invalid percentage for department raise",
                new FaultInfo("INVALID_PERCENTAGE", 
                    "Department raise percentage must be between 0% and " + MAX_RAISE_PERCENTAGE + "%"));
        }
        
        List<Employee> departmentEmployees = dataStore.getEmployeesByDepartment(department);
        List<SalaryUpdateResult> results = new ArrayList<>();
        
        if (departmentEmployees.isEmpty()) {
            throw new EmployeeManagementFault("No employees found in department: " + department,
                new FaultInfo("EMPTY_DEPARTMENT", "No active employees found in the specified department"));
        }
        
        for (Employee employee : departmentEmployees) {
            if ("ACTIVE".equals(employee.getStatus())) {
                try {
                    SalaryUpdateResult result = updateSalaryByPercentage(
                        employee.getEmployeeId(), percentageIncrease, 
                        "Department-wide raise: " + reason);
                    results.add(result);
                } catch (EmployeeManagementFault e) {
                    SalaryUpdateResult failResult = new SalaryUpdateResult();
                    failResult.setSuccess(false);
                    failResult.setEmployeeId(employee.getEmployeeId());
                    failResult.setMessage("Failed: " + e.getMessage());
                    results.add(failResult);
                }
            }
        }
        
        LOGGER.info("Department raise applied. " + results.size() + " employees affected.");
        return results;
    }

    @Override
    public double getEmployeeSalary(int employeeId) throws EmployeeManagementFault {
        validateEmployeeExists(employeeId);
        return dataStore.getEmployee(employeeId).getSalary();
    }

    @Override
    public int submitPerformanceReview(PerformanceReview review) throws EmployeeManagementFault {
        LOGGER.info("Submitting performance review for employee: " + review.getEmployeeId());
        
        validateEmployeeExists(review.getEmployeeId());
        validateEmployeeActive(review.getEmployeeId());
        
        if (review.getRating() < 1 || review.getRating() > 5) {
            throw new EmployeeManagementFault("Invalid rating",
                new FaultInfo("INVALID_RATING", "Rating must be between 1 and 5"));
        }
        
        if (review.getReviewerName() == null || review.getReviewerName().trim().isEmpty()) {
            throw new EmployeeManagementFault("Reviewer name is required",
                new FaultInfo("INVALID_REVIEWER", "Reviewer name must be provided"));
        }
        
        if (review.getComments() == null || review.getComments().trim().isEmpty()) {
            throw new EmployeeManagementFault("Comments are required",
                new FaultInfo("INVALID_COMMENTS", "Review comments must be provided"));
        }
        
        if (review.getReviewDate() == null) {
            review.setReviewDate(new Date());
        }
        
        int reviewId = dataStore.addPerformanceReview(review);
        LOGGER.info("Performance review submitted with ID: " + reviewId);
        return reviewId;
    }

    @Override
    public List<PerformanceReview> getPerformanceReviews(int employeeId) throws EmployeeManagementFault {
        LOGGER.info("Retrieving performance reviews for employee: " + employeeId);
        validateEmployeeExists(employeeId);
        return dataStore.getPerformanceReviews(employeeId);
    }

    @Override
    public PerformanceReview getPerformanceReview(int reviewId) throws EmployeeManagementFault {
        LOGGER.info("Retrieving performance review: " + reviewId);
        PerformanceReview review = dataStore.getPerformanceReview(reviewId);
        if (review == null) {
            throw new EmployeeManagementFault("Performance review not found",
                new FaultInfo("REVIEW_NOT_FOUND", "No performance review found with ID: " + reviewId));
        }
        return review;
    }

    @Override
    public double getAverageRating(int employeeId) throws EmployeeManagementFault {
        LOGGER.info("Calculating average rating for employee: " + employeeId);
        validateEmployeeExists(employeeId);
        
        List<PerformanceReview> reviews = dataStore.getPerformanceReviews(employeeId);
        if (reviews.isEmpty()) {
            throw new EmployeeManagementFault("No reviews found",
                new FaultInfo("NO_REVIEWS", "No performance reviews found for employee: " + employeeId));
        }
        
        return reviews.stream()
                .mapToInt(PerformanceReview::getRating)
                .average()
                .orElse(0.0);
    }

    @Override
    public TerminationResult terminateEmployee(int employeeId, String reason, String terminationType) 
            throws EmployeeManagementFault {
        LOGGER.info("Processing termination for employee: " + employeeId);
        
        validateEmployeeExists(employeeId);
        validateEmployeeActive(employeeId);
        
        if (reason == null || reason.trim().isEmpty()) {
            throw new EmployeeManagementFault("Reason is required",
                new FaultInfo("INVALID_REASON", "A reason must be provided for termination"));
        }
        
        List<String> validTypes = List.of("VOLUNTARY", "INVOLUNTARY", "LAYOFF", "RETIREMENT", "CONTRACT_END");
        if (terminationType == null || !validTypes.contains(terminationType.toUpperCase())) {
            throw new EmployeeManagementFault("Invalid termination type",
                new FaultInfo("INVALID_TERMINATION_TYPE", 
                    "Termination type must be one of: " + String.join(", ", validTypes)));
        }
        
        Employee employee = dataStore.getEmployee(employeeId);
        Date terminationDate = new Date();
        
        // Calculate final pay (simplified: 1 month salary + pro-rated bonus for involuntary/layoff)
        double finalPay = employee.getSalary() / 12; // One month's salary
        if ("INVOLUNTARY".equalsIgnoreCase(terminationType) || "LAYOFF".equalsIgnoreCase(terminationType)) {
            finalPay += (employee.getSalary() / 12) * 2; // Severance: 2 months
        }
        
        employee.setStatus("TERMINATED");
        employee.setTerminationDate(terminationDate);
        employee.setTerminationReason(reason);
        dataStore.updateEmployee(employee);
        
        TerminationResult result = new TerminationResult();
        result.setSuccess(true);
        result.setMessage("Employee terminated successfully");
        result.setEmployeeId(employeeId);
        result.setEmployeeName(employee.getFirstName() + " " + employee.getLastName());
        result.setTerminationDate(terminationDate);
        result.setTerminationReason(reason);
        result.setTerminationType(terminationType.toUpperCase());
        result.setFinalPayAmount(Math.round(finalPay * 100.0) / 100.0);
        
        LOGGER.info("Employee " + employeeId + " terminated. Type: " + terminationType + 
                    ", Final Pay: $" + result.getFinalPayAmount());
        return result;
    }

    @Override
    public boolean reinstateEmployee(int employeeId, double newSalary, String newPosition) 
            throws EmployeeManagementFault {
        LOGGER.info("Reinstating employee: " + employeeId);
        
        if (!dataStore.employeeExists(employeeId)) {
            throw new EmployeeManagementFault("Employee not found",
                new FaultInfo("EMPLOYEE_NOT_FOUND", "No employee found with ID: " + employeeId));
        }
        
        Employee employee = dataStore.getEmployee(employeeId);
        
        if ("ACTIVE".equals(employee.getStatus())) {
            throw new EmployeeManagementFault("Employee is already active",
                new FaultInfo("ALREADY_ACTIVE", "Employee " + employeeId + " is already in active status"));
        }
        
        validateSalary(newSalary);
        
        if (newPosition == null || newPosition.trim().isEmpty()) {
            throw new EmployeeManagementFault("New position is required",
                new FaultInfo("INVALID_POSITION", "A position must be specified for reinstatement"));
        }
        
        employee.setStatus("ACTIVE");
        employee.setSalary(newSalary);
        employee.setPosition(newPosition);
        employee.setTerminationDate(null);
        employee.setTerminationReason(null);
        dataStore.updateEmployee(employee);
        
        LOGGER.info("Employee " + employeeId + " reinstated with position: " + newPosition + 
                    " and salary: $" + newSalary);
        return true;
    }
    
    // Validation helper methods
    private void validateEmployeeExists(int employeeId) throws EmployeeManagementFault {
        if (!dataStore.employeeExists(employeeId)) {
            throw new EmployeeManagementFault("Employee not found",
                new FaultInfo("EMPLOYEE_NOT_FOUND", "No employee found with ID: " + employeeId));
        }
    }
    
    private void validateEmployeeActive(int employeeId) throws EmployeeManagementFault {
        Employee employee = dataStore.getEmployee(employeeId);
        if (!"ACTIVE".equals(employee.getStatus())) {
            throw new EmployeeManagementFault("Employee is not active",
                new FaultInfo("EMPLOYEE_INACTIVE", 
                    "Employee " + employeeId + " has status: " + employee.getStatus() + 
                    ". Only active employees can be modified."));
        }
    }
    
    private void validateSalary(double salary) throws EmployeeManagementFault {
        if (salary < MIN_SALARY) {
            throw new EmployeeManagementFault("Salary too low",
                new FaultInfo("SALARY_TOO_LOW", 
                    "Salary must be at least $" + MIN_SALARY + ". Provided: $" + salary));
        }
        if (salary > MAX_SALARY) {
            throw new EmployeeManagementFault("Salary too high",
                new FaultInfo("SALARY_TOO_HIGH", 
                    "Salary cannot exceed $" + MAX_SALARY + ". Provided: $" + salary));
        }
    }
}

// EmployeeManagementServicePublisher.java
package com.hr;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class EmployeeManagementServicePublisher {
    
    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServicePublisher.class.getName());
    private static final String SERVICE_URL = "http://localhost:8080/hr/employee-management";
    
    private Endpoint endpoint;
    
    public void publish() {
        EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
        endpoint = Endpoint.publish(SERVICE_URL, serviceImpl);
        
        LOGGER.info("========================================");
        LOGGER.info("HR Employee Management SOAP Web Service");
        LOGGER.info("========================================");
        LOGGER.info("Service published at: " + SERVICE_URL);
        LOGGER.info("WSDL available at: " + SERVICE_URL + "?wsdl");
        LOGGER.info("========================================");
        LOGGER.info("Available Operations:");
        LOGGER.info("  - getEmployee");
        LOGGER.info("  - getAllActiveEmployees");
        LOGGER.info("  - getEmployeesByDepartment");
        LOGGER.info("  - updateSalary");
        LOGGER.info("  - updateSalaryByPercentage");
        LOGGER.info("  - applyDepartmentRaise");
        LOGGER.info("  - getEmployeeSalary");
        LOGGER.info("  - submitPerformanceReview");
        LOGGER.info("  - getPerformanceReviews");
        LOGGER.info("  - getPerformanceReview");
        LOGGER.info("  - getAverageRating");
        LOGGER.info("  - terminateEmployee");
        LOGGER.info("  - reinstateEmployee");
        LOGGER.info("========================================");
    }
    
    public void stop() {
        if (endpoint != null && endpoint.isPublished()) {
            endpoint.stop();
            LOGGER.info("Service stopped.");
        }
    }
    
    public boolean isPublished() {
        return endpoint != null && endpoint.isPublished();
    }
    
    public static void main(String[] args) {
        EmployeeManagementServicePublisher publisher = new EmployeeManagementServicePublisher();
        publisher.publish();
        
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down HR Employee Management Service...");
            publisher.stop();
        }));
        
        System.out.println("Press Enter to stop the service...");
        try {
            System.in.read();
        } catch (Exception e) {
            LOGGER.warning("Error reading input: " + e.getMessage());
        }
        
        publisher.stop();
    }
}

